on_write:
let res = #{ action: "Allow" };
if payload.size > 1024 {
    res.action = "Reject";
    res.reason = "Embedded databases have strict payload size constraints (Max 1KB)";
}
res

on_read:
let res = #{ payload: payload };
res.match_found = true;
res

on_lifecycle:
let res = #{};
res.clear_payload = true; // Auto-purge old embedded records to save RAM
res
